<?php declare(strict_types=1);
namespace SecretariaApi\Controllers;
use SecretariaApi\Services\SecretariaService;use Shared\Http\Request;use Shared\Http\Response;
final class SecretariaController{public function __construct(private readonly SecretariaService$s){}private function ok(mixed$d,array$m=[]):Response{return Response::json(['success'=>true,'data'=>$d,'meta'=>(object)$m,'error'=>null]);}public function health():Response{return$this->ok($this->s->health());}public function turmas(Request$r):Response{[$d,$m]=$this->s->turmas($r->query);return$this->ok($d,$m);}public function turma(Request$r,array$p):Response{return$this->ok($this->s->turma((int)$p['turmaId']));}public function alunos(Request$r,array$p):Response{[$d,$m]=$this->s->alunos((int)$p['turmaId'],$r->query);return$this->ok($d,$m);}public function aluno(Request$r,array$p):Response{return$this->ok($this->s->aluno((int)$p['alunoId']));}public function turmaAluno(Request$r,array$p):Response{return$this->ok($this->s->turmaDoAluno((int)$p['alunoId']));}}
